#pragma once

#ifndef ATTENTION_BACKWARD_KERNEL_H
#define ATTENTION_BACKWARD_KERNEL_H

#include <torch/extension.h>

// Fused dropout backward + softmax backward kernel.
// Replaces 5 separate reference operations:
//   1. grad_aw_dropped * mask / (1-p)
//   2. attn_weights.to(float32)
//   3. (gw * aw).sum(dim=-1)
//   4. aw * (gw - sum_term)
//   5. .to(bfloat16)
void fused_dropout_softmax_backward_launcher(
    torch::Tensor& grad_attn_scores,       // output: (B, 80, sq, sk) bf16
    const torch::Tensor& grad_aw_dropped,  // input:  (B, 80, sq, sk) f32
    const torch::Tensor& attn_weights,     // input:  (B, 80, sq, sk) bf16
    const torch::Tensor& dropout_mask,     // input:  (B, 80, sq, sk) bool
    float dropout_scale,
    int batch_size, int num_heads, int seq_len_q, int seq_len_kv,
    cudaStream_t stream
);

#endif

#include "kernel.h"
#include <cuda_runtime.h>
#include <cuda_bf16.h>

constexpr int BLOCK_SIZE = 256;
constexpr int NUM_WARPS = BLOCK_SIZE / 32;

__device__ __forceinline__ float warp_reduce_sum(float val) {
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        val += __shfl_xor_sync(0xFFFFFFFF, val, offset);
    }
    return val;
}

// Fused dropout backward + softmax backward.
// Fixed: __launch_bounds__(256, 4) gives 64 regs/thread (vs 32 with occupancy 8).
// The kernel needs ~42 registers for gw_regs[16] + aw_regs[16] + overhead.
// With occupancy 8 (32 regs), compiler spills to local memory (slow).
// With occupancy 4 (64 regs), no spill.
__global__ void __launch_bounds__(256, 4)
fused_dropout_softmax_backward_kernel(
    __nv_bfloat16* __restrict__ grad_attn_scores,
    const float* __restrict__ grad_aw_dropped,
    const __nv_bfloat16* __restrict__ attn_weights,
    const bool* __restrict__ dropout_mask,
    const float dropout_scale,
    const int seq_len_kv
) {
    const long long row = (long long)blockIdx.x * gridDim.y + blockIdx.y;
    const long long row_off = row * seq_len_kv;

    const int tid = threadIdx.x;
    const int lane = tid & 31;
    const int warp_id = tid >> 5;

    __shared__ float s_warp_sum[NUM_WARPS];

    // Phase 1: Compute gw, accumulate sum_term, store in registers
    float gw_regs[16];
    float aw_regs[16];
    float local_sum = 0.0f;
    int n = 0;

    for (int sk = tid; sk < seq_len_kv; sk += BLOCK_SIZE) {
        float raw = __ldg(&grad_aw_dropped[row_off + sk]);
        bool mask = __ldg(&dropout_mask[row_off + sk]);
        float gw = mask ? raw * dropout_scale : 0.0f;
        float aw = __bfloat162float(__ldg(reinterpret_cast<const __nv_bfloat16*>(&attn_weights[row_off + sk])));

        gw_regs[n] = gw;
        aw_regs[n] = aw;
        local_sum += gw * aw;
        n++;
    }

    // Phase 2: Block-wide reduction
    local_sum = warp_reduce_sum(local_sum);
    if (lane == 0) s_warp_sum[warp_id] = local_sum;
    __syncthreads();

    float total_sum = 0.0f;
    if (tid < NUM_WARPS) total_sum = s_warp_sum[tid];
    if (tid < 32) {
        total_sum = warp_reduce_sum(total_sum);
        if (tid == 0) s_warp_sum[0] = total_sum;
    }
    __syncthreads();
    total_sum = s_warp_sum[0];

    // Phase 3: Compute and write grad_scores (coalesced writes)
    n = 0;
    for (int sk = tid; sk < seq_len_kv; sk += BLOCK_SIZE) {
        float grad_score = aw_regs[n] * (gw_regs[n] - total_sum);
        grad_attn_scores[row_off + sk] = __float2bfloat16(grad_score);
        n++;
    }
}

void fused_dropout_softmax_backward_launcher(
    torch::Tensor& grad_attn_scores,
    const torch::Tensor& grad_aw_dropped,
    const torch::Tensor& attn_weights,
    const torch::Tensor& dropout_mask,
    float dropout_scale,
    int batch_size, int num_heads, int seq_len_q, int seq_len_kv,
    cudaStream_t stream
) {
    dim3 grid(batch_size * num_heads, seq_len_q);
    dim3 block(BLOCK_SIZE);

    fused_dropout_softmax_backward_kernel<<<grid, block, 0, stream>>>(
        reinterpret_cast<__nv_bfloat16*>(grad_attn_scores.data_ptr<at::BFloat16>()),
        grad_aw_dropped.data_ptr<float>(),
        reinterpret_cast<const __nv_bfloat16*>(attn_weights.data_ptr<at::BFloat16>()),
        dropout_mask.data_ptr<bool>(),
        dropout_scale,
        seq_len_kv
    );
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include "kernel.h"

std::vector<torch::Tensor> run(
    const torch::Tensor& grad_attn_output,
    const torch::Tensor& attn_weights,
    const torch::Tensor& attn_weights_dropped,
    const torch::Tensor& value_states,
    const torch::Tensor& dropout_mask,
    double attention_dropout
) {
    TORCH_CHECK(grad_attn_output.is_cuda(), "CUDA required");
    TORCH_CHECK(grad_attn_output.dtype() == torch::kBFloat16, "bfloat16 required");

    const int64_t batch_size = grad_attn_output.size(0);
    const int64_t seq_len_q  = grad_attn_output.size(1);
    const int64_t num_heads      = 80;
    const int64_t num_kv_heads   = 8;
    const int64_t num_groups     = 10;
    const int64_t head_dim       = 128;
    const int64_t seq_len_kv = value_states.size(2);

    const float dropout_scale = attention_dropout > 0.0 ?
        1.0f / (1.0f - static_cast<float>(attention_dropout)) : 1.0f;

    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // ============================================================
    // Prepare f32 inputs (reused across steps)
    // ============================================================
    auto go_f32 = grad_attn_output.transpose(1, 2).to(torch::kFloat32);
    // (B, 80, sq, 128)

    auto v_exp = value_states.unsqueeze(2)
                    .expand({batch_size, num_kv_heads, num_groups, seq_len_kv, head_dim})
                    .reshape({batch_size, num_heads, seq_len_kv, head_dim})
                    .to(torch::kFloat32);
    // (B, 80, sk, 128)

    // ============================================================
    // Allocate ONE shared buffer for the large (B, 80, sq, sk) f32 tensor.
    // Used first as grad_aw_dropped output, then reused as awd_f32.
    // Saves ~5 GB of peak memory allocation.
    // ============================================================
    auto buffer = torch::empty(
        {batch_size, num_heads, seq_len_q, seq_len_kv},
        go_f32.options());

    // ============================================================
    // Step 1: First matmul via cuBLAS (writes into buffer)
    // buffer = go @ V^T : (B,80,sq,128) @ (B,80,128,sk) -> (B,80,sq,sk)
    // ============================================================
    torch::matmul_out(buffer, go_f32, v_exp.transpose(-2, -1));

    // ============================================================
    // Step 2: Fused dropout backward + softmax backward (reads buffer)
    // ============================================================
    auto grad_attn_scores = torch::empty(
        {batch_size, num_heads, seq_len_q, seq_len_kv},
        attn_weights.options());

    fused_dropout_softmax_backward_launcher(
        grad_attn_scores, buffer, attn_weights, dropout_mask,
        dropout_scale,
        static_cast<int>(batch_size), static_cast<int>(num_heads),
        static_cast<int>(seq_len_q), static_cast<int>(seq_len_kv),
        stream
    );

    // ============================================================
    // Step 3: Reuse buffer for awd_f32 (bf16 -> f32 in-place conversion)
    // buffer was grad_aw_dropped, now overwrite with attn_weights_dropped as f32
    // ============================================================
    buffer.copy_(attn_weights_dropped);

    // ============================================================
    // Step 4: Second matmul via cuBLAS
    // grad_v = buffer^T @ go : (B,80,sk,sq) @ (B,80,sq,128) -> (B,80,sk,128)
    // ============================================================
    auto grad_v_expanded = torch::matmul(buffer.transpose(-2, -1), go_f32);

    // GQA aggregation
    grad_v_expanded = grad_v_expanded.reshape(
        {batch_size, num_kv_heads, num_groups, seq_len_kv, head_dim});
    auto grad_value_states = grad_v_expanded.sum(2).to(torch::kBFloat16);

    return {grad_attn_scores, grad_value_states};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Attention backward v17 - buffer reuse + fused dropout/softmax");
}
